func progressCircleClass(status string) string {
	switch status {
	case "passed":
		return "border-emerald-500 bg-emerald-500 text-white"
	case "failed":
		return "border-rose-500 bg-rose-500 text-white"
	case "active", "running":
		return "border-emerald-500 bg-white text-emerald-700 dark:bg-zinc-900 dark:text-emerald-400"
	default:
		return "border-zinc-300 bg-white text-zinc-400 dark:border-zinc-700 dark:bg-zinc-900 dark:text-zinc-600"
	}
}

func progressLabelClass(status string) string {
	switch status {
	case "passed":
		return "text-emerald-600 dark:text-emerald-400"
	case "failed":
		return "text-rose-600 dark:text-rose-400"
	case "active", "running":
		return "text-zinc-800 dark:text-zinc-200"
	default:
		return "text-zinc-400 dark:text-zinc-600"
	}
}

func progressLineClass(status string) string {
	if status == "passed" {
		return "bg-emerald-400"
	}
	return "bg-zinc-200 dark:bg-zinc-700"
}

func stepTitle(n int) string {
	titles := [5]string{"Connect", "Domain", "Preflight", "Install", "Verify"}
	if n >= 0 && n < 5 {
		return titles[n]
	}
	return ""
}

