func checkIcon(s wizard.CheckStatus) string {
	switch s {
	case wizard.StatusPassed:
		return "✓"
	case wizard.StatusFailed:
		return "✗"
	case wizard.StatusWarning:
		return "⚠"
	case wizard.StatusRunning:
		return "⟳"
	case wizard.StatusSkipped:
		return "—"
	default:
		return "○"
	}
}

func checkIconClass(s wizard.CheckStatus) string {
	switch s {
	case wizard.StatusPassed:
		return "text-emerald-500"
	case wizard.StatusFailed:
		return "text-rose-500"
	case wizard.StatusWarning:
		return "text-amber-500"
	case wizard.StatusRunning:
		return "animate-spin text-emerald-400"
	default:
		return "text-zinc-400"
	}
}

func checkLabelClass(s wizard.CheckStatus) string {
	switch s {
	case wizard.StatusFailed:
		return "font-medium text-rose-700 dark:text-rose-400"
	case wizard.StatusWarning:
		return "font-medium text-amber-700 dark:text-amber-400"
	case wizard.StatusSkipped:
		return "text-zinc-400 line-through dark:text-zinc-600"
	default:
		return "text-zinc-700 dark:text-zinc-300"
	}
}

