func installActionLabel(a wizard.InstallAction) string {
	switch a {
	case wizard.ActionInstall:
		return "Install udm-le &amp; Issue Certificate"
	case wizard.ActionRepair:
		return "Repair: Restart Renewal Timer"
	case wizard.ActionUpdate:
		return "Update Config &amp; Re-issue"
	case wizard.ActionRenew:
		return "Force Renew Certificate"
	case wizard.ActionReinstall:
		return "Reinstall udm-le &amp; Re-issue"
	default:
		return "Install &amp; Issue Certificate"
	}
}

